counter_attack.test_skeleton:
// Adversarial test: dimension without hierarchies key
#[test]
fn adversarial_ac1_missing_hierarchies_key() {
    let json = r#"{"measures":[{"unique_name":"m1","name":"Rev"}],"dimensions":[{"unique_name":"d1","name":"Date"}],"calculated_members":[]}""
#;
    let graph = ConceptGraph::from_describe_model(json).unwrap();
    // Only the measure node should be present (no hierarchies or levels)
    assert_eq!(graph.node_count(), 1);
}
// Adversarial test: valid JSON non-object
#[test]
fn adversarial_ac3_json_string_value() {
    assert!(ConceptGraph::from_describe_model(r#""hello""#).is_err());
}
